function playVoiceSound(data, answerWasCorrect){
    if (!AppStorage.getSetting('SETTING_SOUND')){
        return;
    }

    var isOnlyPositiveSound = AppStorage.getSetting('SETTING_POSITIVE');
    if (isOnlyPositiveSound && !answerWasCorrect){
        return;
    }

    var soundInfo = answerWasCorrect ? data.sound.answerWasCorrect : data.sound.answerWasNotCorrect;

    if (data.resetPlayedSounds){
        AppStorage.resetPlayedSounds();
    }
    if (soundInfo.filename){
        var audio = new Audio();
        if (audio.canPlayType("audio/ogg; codecs=vorbis")){
            audio.src = '/audio/voice/ogg/'+soundInfo.filename+'.ogg';
        } else {
            audio.src = '/audio/voice/mp3/'+soundInfo.filename+'.mp3';
        }
        audio.play();
        AppStorage.addPlayedSound(soundInfo.id);
    }
}

function playEndMusic(){
    if (!AppStorage.getSetting('SETTING_SOUND')){
        return;
    }
    var fileIndex = AppStorage.getNextEndSoundIndex();
    var audio = new Audio();
    if (audio.canPlayType("audio/ogg; codecs=vorbis")){
        audio.src = '/audio/ending/ogg/end_'+fileIndex+'.ogg';
    } else {
        audio.src = '/audio/ending/mp3/end_'+fileIndex+'.mp3';
    }
    audio.play();

    // If the user exits the ending page, fade out the audio
    $('#page-game_over').one('pagebeforehide', function(){
        $(audio).animate({volume: 0}, 500);
        setInterval(function(){audio.pause();}, 500);
    });
}

function getFields(callback) {
    if (AppStorage.fields){
        callback();
    } else {
        var args = { isTestMode: false };
        adapter.DbTransfer.getOrderedFields(args, function(err, fields){
            if (err){
                alert('Error', err);
                return;
            }
            AppStorage.fields = fields;
            callback();
        });
    }
}


function fillWithZero(zahl, length) {
    var tmp = '' + zahl;
    var leng = tmp.length;
    if (leng < length) {
        for (; leng < length; leng++) {
            tmp = '0' + tmp;
        }
    }
    return tmp;
}

function getNvcStepColorClass(field){
    var nvc_steps;
    if (AppStorage.getSetting('SETTING_DANCEFLOOR')){
        nvc_steps = {
            1: 'bg-yellow',
            2: 'bg-red',
            3: 'bg-green',
            4: 'bg-blue'
        };
    } else {
        nvc_steps = {
            1: 'bg-blue',
            2: 'bg-red',
            3: 'bg-green',
            4: 'bg-yellow'
        };
    }
    return nvc_steps[field.nvc_step] || 'bg-purple';
}


function getTask() {
    getFields(function(){
        if(AppStorage.isRandomEnabled() === true) {
            var field = AppStorage.fields[Math.floor(Math.random()*AppStorage.fields.length)];
            AppStorage.setCurrentField(field);
        }
        var currentPlayer = AppStorage.getCurrentPlayer();
        if (!currentPlayer){
            // No active game, redirect to front page
            window.location.replace('/');
        }
        $('#current-player').html(currentPlayer.name + ' ist dran');

        var currentField = AppStorage.getCurrentField();
        var excludedTasks = AppStorage.getPlayedTasks();
        var args = {
            // args for task
            fieldId: currentField.id,
            excludedTasks: excludedTasks,

            // args for sound
            voices: AppStorage.getActiveVoices(),
            onlyNvcCompliant: AppStorage.getSetting('SETTING_NVCCONFORM'),
            playedSounds: AppStorage.getPlayedSounds()
        };

        adapter.DbTransfer.getTaskAndSound(args, function(err, data){
            if (err){
                alert('Error', err);
                return;
            }
            var currentTask = data.task;
            AppStorage.addPlayedTask(currentTask._id);
            if (currentTask.resetPlayedTasks){
                AppStorage.resetPlayedTasksForCurrentField();
            }
            AppStorage.setCurrentTask(currentTask); //TODO ist das notwendig oder reicht lokale variable?
            if(currentField.foto === 0) {
                var content = currentTask.content1;
                if(currentField.name.toLowerCase() == 'w1') {
                    var steps = content.split("\n");
                    if(steps.length == 4) {
                        content = '<font color="#cde3f1">' + steps[0] + '</font><font color="#fed9e0">' + steps[1] + '</font><font color="#b8dc7c">' + steps[2] + '</font><font color="#ffff89">' + steps[3] + '</font>';
                    }
                } else if (currentTask.content2){
                    if(currentField.name.toLowerCase() == 'w6') {
                        content = '<font color="#0033FF">Die Aussage:</font><br>' + content + '<br><font color="#0033FF">Die Reaktion:<br></font>' + currentTask.content2 + '<br>';
                    } else if (currentField.name.toLowerCase() == 'w11') {
                        content = '<font color="#0033FF">Die Nachricht:</font><br>' + content + '<br><font color="#0033FF">Die Reaktion:<br></font>' + currentTask.content2 + '<br>';
                    } else {
                        content += '<br/>' + currentTask.content2;
                    }
                }
                $("#task-content").html(content);
            } else {
                var imgName = currentField.name.toLowerCase() + '_' + fillWithZero(currentTask.number, 3);
                var imgHeight = $(window).height() / 3;
                var img = '<img id="task-img" src="img/' +currentField.name.toLowerCase() + '/'+ imgName + '.jpg" height="' + imgHeight + '"/>';
                $("#task-content").html(img);
            }
            var colClass = getNvcStepColorClass(currentField);
            $("#field-text").html(currentField.description).removeClass().addClass(colClass);
            $("#task-content").removeClass().addClass(colClass);

            var choiceList = $('#choicelist');
            var isCorrect;
            choiceList.empty();
            $.each(currentTask.choices, function(i, choice){
                isCorrect = choice.is_correct ? 'is-correct':'';
                choiceList.append('<li><a id="choicebtn" class="bg-gray result-margin choice-btn ' + isCorrect + '">' + choice.content + '</a></li>');

            });
            // listview widget removed — CSS handles styling
            $('.choice-btn').click(function(){
                if($('.choice-btn').prop('disabled')=='true') {return;}
                $('#button-div').show();
                if (currentTask.solution_hint) {
                    $('#explanation-btn').show();
                }
                var selected = $(this);
                var wasCorrect = selected.hasClass('is-correct');
                AppStorage.updateScoreForCurrentPlayer(wasCorrect);
                playVoiceSound(data, wasCorrect);
                var fieldDesc = currentField.description;
                if(wasCorrect) {
                    /* fieldDesc = '<img src="img/gruenerhaken.png" align="bottom"/>&nbsp;&nbsp;&nbsp;&nbsp;Hier stimmen wir überein. <br/><br/>' + fieldDesc; */
                    fieldDesc = 'Hier stimmen wir überein.&nbsp;&nbsp;&nbsp;&nbsp;<img src="img/gruenerhaken.png" align="right"/><br/><br/>' + fieldDesc;
                } else {
                    /* fieldDesc = '<img src="img/roteskreuz.png" align="middle"/>&nbsp;&nbsp;&nbsp;&nbsp;Hier stimmen wir nicht überein. <br/><br/>' + fieldDesc; */
                    fieldDesc = 'Hier stimmen wir nicht überein.&nbsp;&nbsp;&nbsp;&nbsp;<img src="img/roteskreuz.png" align="right"/><br/><br/>' + fieldDesc;
                }
                var colClass = getNvcStepColorClass(currentField);
                $("#field-text").html(fieldDesc).removeClass().addClass(colClass);
                $('.choice-btn').each(function(){
                    var currentBtn = $(this);
                    currentBtn.prop("disabled","true");
                    currentBtn.attr('id',"disabledChoiceBtnLink");
                    if (currentBtn.hasClass('is-correct')){
                        currentBtn.removeClass('bg-gray').addClass('bg-green-result');
                    } else {
                        if (currentBtn.is(selected)){
                            currentBtn.removeClass('bg-gray').addClass('bg-red-result');
                        }
                    }
                });
            });
            $('#help-btn').show();
            $('#button-div').hide();
            $('#explanation-btn').hide();
        });
    });
}

function renderVideoTable(videoList){
    var rows = '';
    $.each(videoList, function(i, video){
        rows +=
            '<tr>' +
                '<td>' +
                    '<a href="' + video.url+ '" target="_blank">' +
                        '<img src="img/video' + video.display_order + '.jpg"/>' +
                    '</a>' +
                '</td>' +
                '<td>' +
                    '<a href="' + video.url+ '" target="_blank">' + video.name + '</a>' +
                '</td>' +
            '</tr>';
    });
    return '<table>' + rows + '</table>';
}

function initHelpVideo(fieldId) {
    var args = { fieldId: fieldId };
    adapter.DbTransfer.getVideosForField(args, function(err, data){
        if (err){
            alert('Error', err);
            return;
        }
        var htmlStr = renderVideoTable(data);
        $('#help_video').html(htmlStr);
    });
}

function initVideoList() {
    var args = {};
    adapter.DbTransfer.getOrderedVideos(args, function(err, data){
        if (err){
            alert('Error', err);
            return;
        }
        var htmlStr = renderVideoTable(data);
        $('#videos').html(htmlStr);
    });
}

function initFieldListPage() {
    getFields(function(){
        var fieldList = $('#fieldlist');
        $.each(AppStorage.fields, function(i, field){
            var colClass = getNvcStepColorClass(field);
            fieldList.append('<li><a class="' + colClass + '" result-margin" href="#page-task" id="field-btn' + i + '">' + field.title + '</a></li>');
            $('#field-btn'+i).click(function(){
                AppStorage.setCurrentField(field);
                getTask();
            });
        });
        // listview widget removed — CSS handles styling
    });
}

