    load('cbSettingKlaus', 'SETTING_KLAUS');
    load('cbSettingAntonia', 'SETTING_ANTONIA');
    load('cbSettingSarina', 'SETTING_SARINA');
    load('cbSettingNvcConform', 'SETTING_NVCCONFORM');
    load('cbSettingPositive', 'SETTING_POSITIVE');
    load('cbSettingDanceFloor', 'SETTING_DANCEFLOOR');
