function initTaskPage(event, ui){
    $('#task-continue-btn').click(function(){
        $('.choice-btn').each(function(){
            $(this).prop("disabled","true");
            $(this).removeAttr('id');
        });
        if(AppStorage.isGameFinished()) {
            playEndMusic();
            $('#task-continue-btn').attr("href", "#page-game_over");
        }
        if(AppStorage.isRandomEnabled()) {
            getTask();
        }
    });
    $('#help-btn').click(function(){
        var currentField = AppStorage.getCurrentField();
        $('#help_txt').html(currentField.help);
        initHelpVideo(currentField.id);
    });
    $('#explanation-btn').click(function(){
        var currentTask = AppStorage.getCurrentTask();
        $('#explanation_txt').html(currentTask.solution_hint);
    });
}


function initStartBtnLink() {
    var random = AppStorage.isRandomEnabled();
    if(random === false) {
        $('#start-btn').prop("href", "#page-field_list");
        $('#task-continue-btn').prop("href", "#page-field_list");
    } else {
        $('#start-btn').prop("href", "#page-task");
        $('#task-continue-btn').prop("href", "#page-task");
    }
}


function getPlayerNames() {
    var names = [];
    $('.playernameinput').each(function(index, el){
        var input = $(el);
        var name = input.val();
        if (!name){
            name = input.attr('placeholder');
        }
        names.push(name);
    });
    return names;
}

function Player(name,totalTasks) {
    this.name=name;
    this.score=0;
    this.totalTasks=totalTasks;
}

function savePlayerNames(playerNames) {
    var players = [];
    $.each(playerNames, function(i, name){
        var p = new Player(name, 0, 0);
        players.push(p);
    });
    store.set('KEY_PLAYERS', players);
}


function addPlayer(addRemoveButton) {
    var presentNames = getPlayerNames();
    var index = presentNames.length;
    if(index > 3) {
        return;
    }

    // Get the last player names from the localstorage
    var defaultNames = [];
    var players = AppStorage.getPlayers();
    if (players){
        $.each(players, function(index, player){
            defaultNames.push(player.name);
        });
    }
    // Add the default names to the list. These names will be used if the latest
    // game had less than 4 players.
    defaultNames = defaultNames.concat(['Antonia', 'Ben', 'Friederike', 'Jan']);

    // Get the next name that's not already used
    var defaultName = '';
    $.each(defaultNames, function(index, name){
        if (presentNames.indexOf(name) < 0){
            defaultName = name;
            return false;
        }
    });

    var removeButton = '';
    if (addRemoveButton){
        removeButton = '<a class="nav-btn bg-red remove-player-btn" id="removeplayer-btn'+index+'"><i class="icon-remove"></i></a>';
    }
    var html =
        '<div class="divname">' +
            '<input type="text" class="playernameinput" name="name" id="name'+index+'" value placeholder='+defaultName+'  />' +
            removeButton +
        '</div>';
    var playerDiv = $("#playernames");
    playerDiv.append(html);
    playerDiv.find('#removeplayer-btn'+index).click(function(){
        $(this).parent('.divname').remove();
    });
}

function initNewGame(event, ui){
    addPlayer(false);
    $('#start-btn').click(function() {
        var cbEnabled = $("#cbManual").prop("checked");
        AppStorage.setRandomEnabled(!cbEnabled);
        AppStorage.resetPlayedSounds();
        AppStorage.resetAllPlayedTasks();
        AppStorage.startGame(getPlayerNames());
        var maxRounds = parseInt($("#select-runden option:selected").val(), 10);
        AppStorage.setMaxNumberOfRounds(maxRounds);
        initStartBtnLink();
    });
    $('#addplayer-btn').click(function(){addPlayer(true);});
}

function getScoreTextForAllPlayers(players) {
    var txt = '';
    for(var i=0;i<players.length;i++) {
        var score = players[i].score;
        var res = 100;
        if(players[i].totalTasks >0) {
            res = Math.round(score * 100 / players[i].totalTasks);
        }
        txt += players[i].name + ': ' + players[i].score + (score === 1?' Punkt':' Punkte');
        txt += ' (' + res + "% korrekt beantwortet)<br/><br/>";
    }
    return txt;
}

function initGameOverScore(players) {
    var imgNumber = AppStorage.getNextImageNameGameOver();
    var txt =
        '<p>' +
            getScoreTextForAllPlayers(players) +
            '<br/>Eine kleine Weisheit zum Spielende' +
        '</p>' +
        '<div align="center" style="margin:5%">' +
            '<img src="img/end/end' + imgNumber + '.jpg" alt="' + endGameQuotes[imgNumber] + '" width="80%" />' +
        '</div>';

    txt += '<div style="margin:20px 0; text-align:center;">' +
            '<a href="#page-task" id="replay-btn" class="bg-green nav-btn">Nochmal spielen</a>' +
            ' <a href="#page-main_menu" class="bg-green nav-btn">Hauptmenü</a>' +
        '</div>';
    $('#finalscore').html(txt);
    $('#finalscore').show();
    store.set('KEY_TOTAL_NUMBER_OF_TASKS', 0);
}

function hideGameOver() {
    $('#finalscore').hide();
}

function initGameOver(event, ui){
    var players = store.get('KEY_PLAYERS');
    if (players === undefined){
        $.mobile.changePage('/');
        return;
    }
    initGameOverScore(players);
    $('#replay-btn').click(function() {
        var players = store.get('KEY_PLAYERS');
        var names = [];
        for (var i=0; i<players.length; i++) {
            names.push(players[i].name);
        }
        AppStorage.startGame(names);
        AppStorage.resetPlayedSounds();
        AppStorage.resetAllPlayedTasks();
        initStartBtnLink();
    });
}

function initAskifnewgame(){
    $('#ask-continue-btn').click(function(){
        if(AppStorage.isRandomEnabled()) {
            getTask();
        }
    });
}

function showAskifnewgame(event, ui) {
    var total = store.get('KEY_TOTAL_NUMBER_OF_TASKS');
    if(total && total > 0) {
        $('#ask-continue-btn').show();
        if(AppStorage.isRandomEnabled()) {
            $('#ask-continue-btn').attr("href", "#page-task");
        } else {
            $('#ask-continue-btn').attr("href", "#page-field_list");
        }
    } else {
        $('#ask-continue-btn').hide();
    }
}

function fillScore() {
    var players = store.get('KEY_PLAYERS');
    if (players === undefined){
        $.mobile.changePage('/');
        return;
    }
    $('#score').html(getScoreTextForAllPlayers(players));
}


var initApp = function(){
    $('#page-settings').on('pagecreate', initSettings);
    $('#page-settings').on('pageshow', loadSettings);
    $('#page-nvc_videos').on('pagecreate', initVideoList);
    $('#page-field_list').on('pagecreate', initFieldListPage);
    $('#page-task').on('pagecreate', initTaskPage);
    $('#dialog-score').on('pageshow', fillScore);
    $('#page-new_game').on('pagecreate', initNewGame);
    $('#page-game_over').on('pageshow', initGameOver);
    $('#page-game_over').on('pagehide', hideGameOver);
    $('#page-askifnewgame').on('pagecreate', initAskifnewgame);
    $('#page-askifnewgame').on('pageshow', showAskifnewgame);
};


/* exported initApp */


AppStorage = {
    fields: undefined,

    setCurrentTask: function(task){
        store.set('KEY_CURRENT_TASK', task);
    },
    getCurrentTask: function() {
        return store.get('KEY_CURRENT_TASK');
    },
    setCurrentField: function(field){
        store.set('KEY_CURRENT_FIELD', field);
    },
    getCurrentField: function() {
        return store.get('KEY_CURRENT_FIELD');
    },

    /* KEY_PLAYERS is an array of Player-objects. The first element in the array
     * is always the current player. After the current player is done, the
     * first element in the array will be put to the end of the array.
     */
    startGame: function(playerNames) {
        savePlayerNames(playerNames);
        store.set('KEY_TOTAL_NUMBER_OF_TASKS', 0);
        if (AppStorage.isRandomEnabled()){
            getTask();
        }
    },

    updateScoreForCurrentPlayer: function(answerWasCorrect) {
        var players = store.get('KEY_PLAYERS');
        var currentPlayer = players.shift();
        currentPlayer.totalTasks += 1;
        if (answerWasCorrect){
            currentPlayer.score += 1;
        }
        players.push(currentPlayer);
        store.set('KEY_PLAYERS', players);
        store.set('KEY_TOTAL_NUMBER_OF_TASKS', store.get('KEY_TOTAL_NUMBER_OF_TASKS') + 1);
    },
    getPlayers: function() {
        return store.get('KEY_PLAYERS');
    },
    getCurrentPlayer: function() {
        var players = store.get('KEY_PLAYERS');
        if (!players){
            return null;
        }
        return players[0];
    },
    getLastPlayerForScore: function() {
        var players = store.get('KEY_PLAYERS');
        if (!players){
            return null;
        }
        return players[players.length-1];
    },
    setRandomEnabled: function(isEnabled) {
        store.set('KEY_SELECT_FIELDS_MANUALLY', !isEnabled);
    },
    isRandomEnabled: function() {
        return !store.get('KEY_SELECT_FIELDS_MANUALLY');
    },
    getNumberOfRounds: function() {
        return store.get('KEY_NUMBER_OF_ROUNDS');
    },
    setMaxNumberOfRounds: function(max) {
        store.set('KEY_MAX_NUMBER_OF_ROUNDS', max);
    },
    isGameFinished: function() {
        var totalNumberOfTasks = store.get('KEY_TOTAL_NUMBER_OF_TASKS');
        var numberOfPlayers = store.get('KEY_PLAYERS').length;
        var maxRounds = store.get('KEY_MAX_NUMBER_OF_ROUNDS');
        var rest = maxRounds * numberOfPlayers - totalNumberOfTasks;
        return rest === 0;
    },
    addPlayedTask: function(task) {
        var playedTasks = store.get('KEY_PLAYED_TASKS');
        var playedTasksForCurrentField = playedTasks[AppStorage.getCurrentField().name] || [];
        playedTasksForCurrentField.push(task);
        playedTasks[AppStorage.getCurrentField().name] = playedTasksForCurrentField;
        store.set('KEY_PLAYED_TASKS', playedTasks);
    },
    getPlayedTasks: function() {
        var allPlayedTasks = store.get('KEY_PLAYED_TASKS');
        if(allPlayedTasks === undefined) {
            return [];
        }
        var tasks = allPlayedTasks[AppStorage.getCurrentField().name];
        if(tasks === undefined) {
            tasks = [];
            allPlayedTasks[AppStorage.getCurrentField().name] = tasks;
            store.set('KEY_PLAYED_TASKS', allPlayedTasks);
        }
        return tasks;
    },
    resetPlayedTasksForCurrentField: function() {
        var playedTasks = store.get('KEY_PLAYED_TASKS');
        playedTasks[AppStorage.getCurrentField().name] = [];
        store.set('KEY_PLAYED_TASKS', playedTasks);
    },
    resetAllPlayedTasks: function() {
        store.set('KEY_PLAYED_TASKS', {});
    },
    addPlayedSound: function(sound) {
        var sounds = store.get('KEY_PLAYED_SOUNDS') || [];
        sounds.push(sound);
        store.set('KEY_PLAYED_SOUNDS', sounds);
    },
    getPlayedSounds: function() {
        return store.get('KEY_PLAYED_SOUNDS') || [];
    },
    resetPlayedSounds: function() {
        store.set('KEY_PLAYED_SOUNDS', []);
    },
    getSetting: function(key) {
        var value = store.get(key);
        if (value === undefined) {
            value = defaults[key];
        }
        return value;
    },

    getActiveVoices: function(){
        var voices = [];
        if (AppStorage.getSetting('SETTING_KLAUS')){
            voices.push('Klaus');
        }
        if (AppStorage.getSetting('SETTING_ANTONIA')){
            voices.push('Antonia');
        }
        if (AppStorage.getSetting('SETTING_SARINA')){
            voices.push('Sarina');
        }
        return voices;
    },

    getNextImageNameGameOver: function() {
        var numberOfImages = 42;
        var imgIndex = store.get('KEY_IMAGES_GAME_OVER_INDEX');
        if (imgIndex === undefined || imgIndex === numberOfImages) {
            imgIndex = 0;
        }
        imgIndex = imgIndex + 1;
        store.set('KEY_IMAGES_GAME_OVER_INDEX', imgIndex);
        return imgIndex;
    },

    getNextEndSoundIndex: function(){
        var numberOfSounds = 8;
        var index = store.get('KEY_AUDIO_GAME_OVER_INDEX');
        if (index === undefined || index === numberOfSounds){
            index = 0;
        }
        index += 1;
        store.set('KEY_AUDIO_GAME_OVER_INDEX', index);
        return index;
    }
};
var _makeTransferFunction = function(name){
    var func = function(args, callback){
        var settings = {
            data: JSON.stringify(args),
            success: function(data){callback(null, data);},
            error: function(jqXHR, textStatus, errorThrown){callback(textStatus+errorThrown);},
            type: 'POST',
            contentType: 'application/json'
        };
        $.ajax('/ajax/'+name, settings);
    };
    return func;
};

var adapter = {
    DbTransfer: {
        getOrderedFields:   _makeTransferFunction('getOrderedFields'),
        getRandomTask:      _makeTransferFunction('getRandomTask'),
        getStaticText:      _makeTransferFunction('getStaticText'),
        getVideosForField:  _makeTransferFunction('getVideosForField'),
        getOrderedVideos:   _makeTransferFunction('getOrderedVideos'),
        getRandomSound:     _makeTransferFunction('getRandomSound'),
        getTaskAndSound:    _makeTransferFunction('getTaskAndSound')
    }
};

/* exported adapter */
